# Check server architectures and existing runner installations
for server in "31.97.102.48" "92.4.83.28" "129.213.82.37"; do
  echo "=== $server ===";
  ssh -o ConnectTimeout=5 ubuntu@$server 'uname -m; ls /home/*/actions-runner/ 2>/dev/null || echo "no runner dir"; systemctl list-units --type=service | grep actions 2>/dev/null || echo "no runner service"' 2>&1;
  echo;
done

